SELECT *
FROM vr.tn_vr
WHERE oprtr_id   = #{oprtrId}
  AND rprt_yr    = #{rprtYr}
  AND vr_type_cd = #{vrTypeCd}
  AND vr_ver     = #{vrVer}
  AND use_end_dt > NOW()

SELECT *
FROM vr.tn_vr
WHERE oprtr_id   = #{oprtrId}
  AND rprt_yr    = #{rprtYr}
  AND vr_type_cd = #{vrTypeCd}
  AND use_end_dt > NOW()
ORDER BY vr_ver DESC
LIMIT 1

SELECT COUNT(*)
FROM vr.tn_vr
WHERE use_end_dt > NOW()

    AND oprtr_id = #{oprtrId}


    AND rprt_yr = #{rprtYr}


    AND vr_type_cd = #{vrTypeCd}


    AND vr_st_cd = #{vrStCd}


    AND vrfcn_inst_id = #{vrfcnInstId}

SELECT *
FROM vr.tn_vr
WHERE use_end_dt > NOW()

    AND oprtr_id = #{oprtrId}


    AND rprt_yr = #{rprtYr}


    AND vr_type_cd = #{vrTypeCd}


    AND vr_st_cd = #{vrStCd}


    AND vrfcn_inst_id = #{vrfcnInstId}

ORDER BY rprt_yr DESC, oprtr_id, vr_type_cd, vr_ver DESC
LIMIT #{pageSize} OFFSET #{offset}
